external_knowledge:
- "High average salary" is defined as greater than $50,000;
- "High average satisfaction" is defined as greater than 8 on a scale of 1-10;
- "High average rating" is defined as greater than 4 on a scale of 1-5.

- "garden of IT training programs" refers to the collection of IT training programs;
- "experienced gardeners" refers to trainers with more than 5 years of experience;
- "unemployed saplings" refers to participants who are unemployed.

sql:
SELECT COUNT(*) AS online_vocational_programs
FROM training_programs
WHERE program_type = 'vocational' AND program_format = 'online';

SELECT AVG(enrollment_count) AS average_enrollment_across_all_programs
FROM (
  SELECT program_id, COUNT(enrollment_id) AS enrollment_count
  FROM enrollments
  GROUP BY program_id
) AS program_enrollments;

SELECT AVG(salary) AS average_salary
FROM program_outcomes
WHERE job_placement = 1;

